#!/usr/bin/env bash
set -euo pipefail

project_root="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"

require_pattern() {
  local path="$1"
  local pattern="$2"

  if ! grep -F -- "$pattern" "$project_root/$path" >/dev/null; then
    printf 'missing swarm-ready gate pattern in %s: %s\n' "$path" "$pattern" >&2
    exit 1
  fi
}

reject_pattern() {
  local path="$1"
  local pattern="$2"

  if grep -F -- "$pattern" "$project_root/$path" >/dev/null; then
    printf 'unexpected swarm-ready gate pattern in %s: %s\n' "$path" "$pattern" >&2
    exit 1
  fi
}

bash -n "$project_root/scripts/test-native-claspc.sh" "$project_root/scripts/test-native-claspc-smoke.sh" "$project_root/scripts/test-native-export-host-content-scope.sh" "$project_root/scripts/test-int-builtins.sh" "$project_root/scripts/test-dict-builtins.sh" "$project_root/scripts/test-try-decode.sh" "$project_root/scripts/test-model-boundary.sh" "$project_root/scripts/test-native-runtime-smoke.sh" "$project_root/scripts/test-verify-all-smoke.sh" "$project_root/scripts/test-agent-command-template.sh" "$project_root/scripts/test-standalone-swarm-surfaces.sh" "$project_root/scripts/test-local-source-edit-workspace.sh" "$project_root/scripts/test-local-agent-capability-closure.sh" "$project_root/scripts/test-goal-manager-agent-command-template.sh" "$project_root/scripts/test-goal-manager-default-planner-command.sh" "$project_root/scripts/test-swarm-ready-benchmark.sh" "$project_root/scripts/test-swarm-policy-helpers.sh" "$project_root/scripts/test-swarm-destructive-policy.sh" "$project_root/scripts/test-swarm-filesystem-kernel-policy.sh" "$project_root/scripts/test-swarm-memory.sh" "$project_root/scripts/test-swarm-priority.sh" "$project_root/scripts/test-swarm-spawn-policy.sh" "$project_root/scripts/test-swarm-context-pack.sh" "$project_root/scripts/test-swarm-semantic-summary-index.sh" "$project_root/scripts/test-resource-guard-policy.sh" "$project_root/benchmarks/test-benchmark-prep-cache.sh"
bash -n "$project_root/scripts/test-agent-backend-static.sh"
bash -n "$project_root/scripts/test-agent-ergonomics-helpers.sh"
bash -n "$project_root/scripts/clasp-manager-worktree-checkpoint.sh"
bash -n "$project_root/scripts/clasp-swarm-preflight.sh"
bash -n "$project_root/scripts/clasp-swarm-supervise.sh"
bash -n "$project_root/scripts/test-swarm-preflight.sh"
bash -n "$project_root/scripts/test-goal-manager-mailbox-capability-details.sh"
bash -n "$project_root/scripts/test-safe-workspace-static.sh"
bash -n "$project_root/scripts/test-generated-state-cleanup-plan-static.sh"
bash -n "$project_root/scripts/test-goal-manager-generated-cleanup-health.sh"
bash -n "$project_root/scripts/test-goal-manager-planner-report-decode.sh"
bash -n "$project_root/scripts/test-goal-manager-resource-health.sh"
bash -n "$project_root/scripts/test-service-decode.sh"
bash -n "$project_root/examples/swarm-kernel/scripts/verify.sh"
node "$project_root/scripts/check-promoted-native-image-exports.mjs" >/dev/null

if [[ -e "$project_root/examples/swarm-native/GoalManagerProgram.clasp" || -e "$project_root/examples/swarm-native/GoalManagerProgram2.clasp" ]]; then
  printf 'stale monolithic GoalManager program copies should stay retired; use GoalManager.wrapper.clasp or GoalManagerProgram2.split.clasp\n' >&2
  exit 1
fi

for retired_path in \
  "cabal.project" \
  "clasp-compiler.cabal" \
  "app/Main.hs" \
  "test/Main.hs" \
  "src/scripts/render-primary-source.hs" \
  "deprecated/bootstrap"; do
  if [[ -e "$project_root/$retired_path" ]]; then
    printf 'retired Haskell bootstrap surface should stay absent: %s\n' "$retired_path" >&2
    exit 1
  fi
done

